SELECT access_type, MAX(access_duration) AS max_access_duration
FROM weather_access
GROUP BY access_type;

SELECT city_name 
FROM cities 
WHERE EXISTS (SELECT * FROM weather_data WHERE weather_data.city_id = cities.city_id);

SELECT u.user_name
FROM users u
WHERE (
    SELECT COUNT(DISTINCT wa.city_id)
    FROM weather_access wa
    WHERE wa.user_id = u.user_id
) = (
    SELECT COUNT(*)
    FROM cities
);

SELECT
  (SELECT AVG(humidity) FROM weather_data WHERE city_id = 1) AS avg_humidity_current,
  (SELECT AVG(humidity) FROM historical_weather WHERE city_id = 1) AS avg_humidity_historical;
